#include <iostream>
#include <string>

class Label {
private:
    std::string m_name{};

public:
    void setName(const std::string& name) { m_name = name; }
    const std::string& getName() const    { return m_name; }
};

int main() {
    std::string word;
    int n;
    std::cin >> word >> n;

    Label lbl;
    lbl.setName(word);

    for (int i = 1; i <= n; ++i) {
        std::cout << lbl.getName() << ": " << i << '\n';
    }

    return 0;
}

